const runStatus = $input.first().json;
const datasetId = runStatus?.data?.defaultDatasetId;
const runId = runStatus?.data?.id || 'unknown';

if (!datasetId) {
  return [{
    json: {
      error: true,
      message: 'No defaultDatasetId in run status. runId=' + runId + ' status=' + (runStatus?.data?.status || 'unknown')
    }
  }];
}

const token = 'YOUR_APIFY_TOKEN';

async function fetchDataset(dsId, attempt) {
  const url = `https://api.apify.com/v2/datasets/${dsId}/items?token=${token}`;
  const raw = await this.helpers.httpRequest({
    method: 'GET',
    url,
    encoding: 'utf-8',
    returnFullResponse: false,
    timeout: 60000,
    headers: { 'Accept': 'application/json' },
  });
  let parsed = raw;
  if (typeof raw === 'string') {
    try { parsed = JSON.parse(raw); } catch (e) {
      throw new Error(`JSON parse failed (attempt ${attempt}): ${raw.substring(0, 200)}`);
    }
  }
  return parsed;
}

let datasetItems;
let lastErr;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    datasetItems = await fetchDataset.call(this, datasetId, attempt);
    if (Array.isArray(datasetItems) && datasetItems.length > 0) break;
    if (attempt < 3) {
      await new Promise(r => setTimeout(r, 15000));
    }
  } catch (err) {
    lastErr = err;
    if (attempt < 3) {
      await new Promise(r => setTimeout(r, 15000));
    }
  }
}

if (lastErr && (!datasetItems || !Array.isArray(datasetItems) || datasetItems.length === 0)) {
  return [{
    json: {
      error: true,
      message: `Fetch dataset failed after 3 attempts: ${lastErr.message}`,
      datasetId, runId
    }
  }];
}

if (!datasetItems || !Array.isArray(datasetItems) || datasetItems.length === 0) {
  return [{
    json: {
      error: true,
      message: `Dataset ${datasetId} empty after 3 attempts (runId=${runId}). Type=${typeof datasetItems}`,
      datasetId, runId
    }
  }];
}

const central = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const [cy,cm,cd] = central.split('-').map(Number);
const today = new Date(cy, cm-1, cd);
const day = today.getDay();
if (day === 0) today.setDate(today.getDate() - 2);
else if (day === 6) today.setDate(today.getDate() - 1);
const scrapeDate = today.getFullYear()+'-'+String(today.getMonth()+1).padStart(2,'0')+'-'+String(today.getDate()).padStart(2,'0');

const agents = datasetItems.filter(item => !item._type);
const poolItem = datasetItems.find(item => item._type === 'pool_data');
const poolAgents = poolItem ? (poolItem.pool_agents || []) : [];
const poolInventory = poolItem ? (poolItem.pool_inventory || []) : [];
const perfItem = datasetItems.find(item => item._type === 'agent_performance');
const perfAgents = perfItem ? (perfItem.agents || []) : [];
const reconciliationItems = datasetItems.filter(item => item._type === 'pool_sales_reconciliation');

return [{
  json: {
    scrape_date: scrapeDate,
    agents: agents,
    pool_agents: poolAgents,
    pool_inventory: poolInventory,
    perf_agents: perfAgents,
    pool_reconciliation: reconciliationItems
  }
}];

/**
 * DSB daily scrape — Slack production digest (all active agents).
 * All agents are remote (RMT). No site filtering or grouping.
 * Merge: node n8n/snippets/merge-dsb-daily-slack.mjs
 *
 * Template uses YOUR_* placeholders; filled by generate-dsb-daily-LIVE.mjs for local paste.
 */
const payload = $node["Fetch Dataset & Build Payload"].json;
const agents = payload.agents || [];
const scrapeDate = payload.scrape_date;
const apikey = "YOUR_ROLI_ANON_KEY";
const base = "https://YOUR_SUPABASE_PROJECT_REF.supabase.co/rest/v1";
const hdr = { apikey: apikey };

const rosterNames = new Set();
const aliasToCanonical = {};
try {
  const [roster, aliases] = await Promise.all([
    this.helpers.httpRequest({ method: "GET", url: base + "/agents?select=name&is_active=eq.true", headers: hdr, json: true }),
    this.helpers.httpRequest({ method: "GET", url: base + "/agent_name_aliases?select=crm_name,canonical_name", headers: hdr, json: true }),
  ]);
  for (const r of roster) rosterNames.add(r.name);
  for (const a of (aliases || [])) aliasToCanonical[a.crm_name] = a.canonical_name;
} catch (e) {}

function resolveAgent(crmName) {
  if (rosterNames.has(crmName)) return crmName;
  const canonical = aliasToCanonical[crmName];
  if (canonical && rosterNames.has(canonical)) return canonical;
  return null;
}

function inRoster(agentName) {
  if (rosterNames.size === 0) return true;
  return resolveAgent(agentName) !== null;
}

const yd = new Date(scrapeDate);
yd.setDate(yd.getDate() - 1);
if (yd.getDay() === 0) yd.setDate(yd.getDate() - 2);
if (yd.getDay() === 6) yd.setDate(yd.getDate() - 1);
const yesterdayStr = yd.toISOString().slice(0, 10);
let yData = [];
try {
  yData = await this.helpers.httpRequest({
    method: "GET",
    url:
      base +
      "/daily_scrape_data?select=agent_name,ib_sales,ob_sales,custom_sales,ib_premium,ob_premium,custom_premium&scrape_date=eq." +
      yesterdayStr,
    headers: hdr,
    json: true,
  });
} catch (e) {}

let ySales = 0, yPremium = 0;
for (const a of yData) {
  if (!inRoster(a.agent_name)) continue;
  ySales += (a.ib_sales || 0) + (a.ob_sales || 0) + (a.custom_sales || 0);
  yPremium += (a.ib_premium || 0) + (a.ob_premium || 0) + (a.custom_premium || 0);
}

let totalS = 0, totalP = 0, totalIBL = 0, totalOBL = 0, totalAllSales = 0, totalBonS = 0, totalBonP = 0, agentCount = 0;

for (const a of agents) {
  const name = a.agent_name || a.name;
  if (!inRoster(name)) continue;
  agentCount++;
  totalAllSales += (a.ib_sales || 0) + (a.ob_sales || 0);
  totalBonS += a.custom_sales || 0;
  totalP += (a.ib_premium || 0) + (a.ob_premium || 0);
  totalBonP += a.custom_premium || 0;
  totalIBL += a.ib_leads_delivered || 0;
  totalOBL += a.ob_leads_delivered || 0;
}

const poolAgentsData = payload.pool_agents || [];
const inRosterPool = poolAgentsData.filter((a) => inRoster(a.agent_name));
const totalPoolSalesMade = inRosterPool.reduce((s, a) => s + (a.sales_made || 0), 0);
const totalPoolAssigns = inRosterPool.reduce((s, a) => s + (a.self_assigned_leads || 0), 0);

const totalIBS = Math.max(0, totalAllSales - totalPoolSalesMade);
totalS = totalAllSales + totalBonS;
totalP += totalBonP;

const fmt = (n) => "$" + Math.round(n).toLocaleString();
const arrow = (curr, prev) => {
  if (prev === 0 && curr === 0) return "";
  if (prev === 0) return " :arrow_up:";
  const pct = (((curr - prev) / prev) * 100).toFixed(0);
  if (curr > prev) return " :chart_with_upwards_trend: +" + pct + "%";
  if (curr < prev) return " :chart_with_downwards_trend: " + pct + "%";
  return " :arrow_right: 0%";
};

const now = new Date();
const centralHour = Number(now.toLocaleString("en-US", { timeZone: "America/Chicago", hour: "numeric", hour12: false }));
const centralMin = String(now.toLocaleString("en-US", { timeZone: "America/Chicago", minute: "2-digit" })).padStart(2, "0");
const ampm = centralHour >= 12 ? "PM" : "AM";
const h12 = centralHour > 12 ? centralHour - 12 : centralHour === 0 ? 12 : centralHour;
const time = h12 + ":" + centralMin + " " + ampm;

// Under the unified all-remote model the legacy `ob_*` bucket holds
// non-standard inbound types (missed inbound, FEX, exclusive, recycled).
// Combine with IB so the digest reports a single honest "Inbound" line.
const totalInboundLeads = totalIBL + totalOBL;
const totalInboundCR = totalInboundLeads > 0 ? ((totalIBS / totalInboundLeads) * 100).toFixed(1) + "%" : "--";
const poolCR = totalPoolAssigns > 0 ? ((totalPoolSalesMade / totalPoolAssigns) * 100).toFixed(1) + "%" : "--";
const overallCR = totalInboundLeads > 0 ? ((totalS / totalInboundLeads) * 100).toFixed(1) + "%" : "--";

const hasYesterday = yData.length > 0;
const vsYesterday = hasYesterday
  ? "\n_vs yesterday:_ Sales" + arrow(totalS, ySales) + "  |  Premium" + arrow(totalP, yPremium)
  : "";

const poolInventory = payload.pool_inventory || [];
const poolCalls = inRosterPool.reduce((s, a) => s + (a.calls_made || 0), 0);
const poolAnswered = inRosterPool.reduce((s, a) => s + (a.answered_calls || 0), 0);
const poolLong = inRosterPool.reduce((s, a) => s + (a.long_calls || 0), 0);
const contactRate = poolCalls > 0 ? ((poolAnswered / poolCalls) * 100).toFixed(0) : "--";
const totalPoolLeads = poolInventory.reduce((s, i) => s + (i.total_leads || 0), 0);
const poolAgentsActive = inRosterPool.filter(a => (a.calls_made || 0) > 0).length;
let poolSection = "";
if (poolCalls > 0) {
  poolSection = "\n\n:busts_in_silhouette: *Pool activity:*  " + poolAgentsActive + " agents  |  " +
    poolCalls + " dials  |  " + contactRate + "% contact  |  " + poolLong + " long calls" +
    (totalPoolLeads > 0 ? "\n:package: " + totalPoolLeads + " contactable leads in pool" : "");
}

const message = {
  text: "DSB production digest \u2014 " + scrapeDate,
  blocks: [
    { type: "header", text: { type: "plain_text", text: "DSB production digest \u2014 " + scrapeDate, emoji: true } },
    { type: "section", text: { type: "mrkdwn", text: "*" + agentCount + " agents* at *" + time + " CST*" } },
    { type: "divider" },
    { type: "section", text: { type: "mrkdwn", text:
      "*" + totalS + " sales  |  " + fmt(totalP) + " premium*\n" +
      "Inbound: *" + totalIBS + "* sales / *" + totalInboundLeads + "* leads → *" + totalInboundCR + "* CR\n" +
      "Pool: *" + totalPoolSalesMade + "* sales / *" + totalPoolAssigns + "* assigns → *" + poolCR + "* CR\n" +
      "Overall: *" + overallCR + "* (" + totalS + "/" + totalInboundLeads + " leads)" +
      (totalBonS > 0 ? "\n:star: *Bonus / custom:*  " + totalBonS + " sales  |  " + fmt(totalBonP) + " premium" : "") +
      vsYesterday + poolSection
    }},
    { type: "context", elements: [{ type: "mrkdwn", text: "Report date: " + scrapeDate + "  |  Ingested to Supabase  |  Next run in ~1 hour" }] },
  ],
};

return [{ json: message }];

const payload = $node['Fetch Dataset & Build Payload'].json;
const poolAgents = payload.pool_agents || [];
const poolInventory = payload.pool_inventory || [];

return [{
  json: {
    scrape_date: payload.scrape_date,
    agents: poolAgents,
    inventory: poolInventory
  }
}];

const payload = $node['Fetch Dataset & Build Payload'].json;
const perfAgents = payload.perf_agents || [];

return [{
  json: {
    scrape_date: payload.scrape_date,
    agents: perfAgents
  }
}];

const payload = $node['Fetch Dataset & Build Payload'].json;
const items = payload.pool_reconciliation || [];

if (items.length === 0) {
  return [{ json: { _empty: true, count: 0 } }];
}

return items.map(item => ({
  json: {
    scrape_date: item.scrape_date,
    agents: item.pool_agents || [],
    sales_only: true
  }
}));
